solution_code:
#include <iostream>
#include <memory>

struct Account
{
    int balance{};
    Account(int initial) : balance{ initial } {}

    void apply(char op, int amount)
    {
        if (op == 'd')
            balance += amount;
        else if (op == 'w')
            balance -= amount;
    }
};

int main()
{
    int initial{};
    int k{};
    std::cin >> initial >> k;

    auto acct{ std::make_unique<Account>(initial) };
    for (int i{ 0 }; i < k; ++i)
    {
        char op{};
        int amount{};
        std::cin >> op >> amount;
        acct->apply(op, amount);
    }

    auto owner{ std::move(acct) };

    std::cout << "original null: " << std::boolalpha << (acct == nullptr) << '\n';
    std::cout << "balance: " << owner->balance << '\n';

    return 0;
}

