solution_code:
#include <iostream>
#include <memory>
#include <vector>

struct Item
{
    int value;
    Item(int v) : value{ v } {}
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<std::unique_ptr<Item>> items;
    for (int i{ 0 }; i < n; ++i)
    {
        int v{};
        std::cin >> v;
        items.push_back(std::make_unique<Item>(v));
    }

    std::size_t maxIdx{ 0 };
    for (std::size_t i{ 1 }; i < items.size(); ++i)
        if (items[i]->value > items[maxIdx]->value)
            maxIdx = i;

    auto best{ std::move(items[maxIdx]) };
    std::cout << "extracted: " << best->value << '\n';

    int remaining{ 0 };
    for (const auto& p : items)
        if (p != nullptr)
            remaining += p->value;
    std::cout << "remaining sum: " << remaining << '\n';
    std::cout << "vector size: " << items.size() << '\n';

    return 0;
}
